// Obtendo o valor da variável
var dataHora = $now;

// Função para formatar os valores
function formatarDataHoraCompleta(dataHora) {
    const dataObj = new Date(dataHora);

    // Obtendo dia da semana
    const diasSemana = ["Domingo", "Segunda-feira", "Terça-feira", "Quarta-feira", "Quinta-feira", "Sexta-feira", "Sábado"];
    const diaSemana = diasSemana[dataObj.getDay()];

    // Obtendo valores individuais
const dia = String(dataObj.getDate()).padStart(2, '0');
const mes = String(dataObj.getMonth() + 1).padStart(2, '0');
const ano = String(dataObj.getFullYear()); // Convertendo para string


    // Formatando data completa
    const dataFormatada = `${dia}-${mes}-${ano}`;

    // Formatando hora
    const hora = String(dataObj.getHours()).padStart(2, '0');
    const minuto = String(dataObj.getMinutes()).padStart(2, '0');
    const segundo = String(dataObj.getSeconds()).padStart(2, '0');
    const horaFormatada = `${hora}:${minuto}:${segundo}`;

    // Criando a string completa
    const dataHoraCompleta = `${diaSemana}, ${dataFormatada} - ${horaFormatada}`;

    // Formatando para timestampz
    const timestampz = dataObj.toISOString();

    return {
        dia_semana: diaSemana,
        dia: dia,
        mes: mes,
        ano: ano,
        data: dataFormatada,
        horario: horaFormatada,
        data_hora_completa: dataHoraCompleta,
        timestampz: timestampz
    };
}

const resultado = formatarDataHoraCompleta(dataHora);
console.log(`Timestampz: ${resultado.timestampz}`);

