function identificarTipoDeDado(input) {
    return input.map(update => {
        if (!update.json || !update.json.message) {
            return { tipo: "Mensagem inválida" };
        }

        if (update.json.message.photo) {
            return { tipo: "imageMessage", conteudo: update.json.message.photo };
        } else if (update.json.message.text) {
            return { tipo: "conversation", conteudo: update.json.message.text };
        } else if (update.json.message.voice) {
            return { tipo: "audioMessage", conteudo: update.json.message.voice };
        } else if (update.json.message.video) {
            return { tipo: "videoMessage", conteudo: update.json.message.video };
        } else if (update.json.message.document) {
            return { tipo: "documentMessage", conteudo: update.json.message.document };
        } else if (update.json.message.location) {
            return { tipo: "Localização", conteudo: update.json.message.location };
        } else {
            return { tipo: "Tipo desconhecido" };
        }
    });
}

// Retornar os dados corretamente no n8n
return identificarTipoDeDado($input.all());

// Função auxiliar para acessar propriedades aninhadas com segurança
function safeGet(obj, path) {
  try {
    return path.split('.').reduce((current, key) => current?.[key], obj) || '';
  } catch (error) {
    return '';
  }
}

// Função para limpar sufixos indesejados do número
function cleanPhoneNumber(phone) {
  if (!phone) return '';
  // Remove padrões como ":39" ou qualquer ":número" antes do @
  return phone.replace(/:\d+(@|$)/g, '$1');
}

// Acessando os dados de entrada usando as expressões corretas com verificações de segurança
const webhookData = $('Webhook').first()?.json;
const inputData = $input.first()?.json;

const remoteJid = cleanPhoneNumber(safeGet(webhookData, 'body.data.key.remoteJid'));
const senderLid = cleanPhoneNumber(safeGet(webhookData, 'body.data.key.senderLid'));
const previousRemoteJid = cleanPhoneNumber(safeGet(inputData, 'body.data.key.previousRemoteJid'));
const sender = cleanPhoneNumber(safeGet(webhookData, 'body.sender'));

// Debug - vamos ver o que temos
console.log('remoteJid:', remoteJid);
console.log('senderLid:', senderLid);
console.log('previousRemoteJid:', previousRemoteJid);
console.log('sender:', sender);

// Determinando whatsapp_user (baseado no remoteJid)
let whatsapp_user = '';
if (remoteJid) {
  whatsapp_user = remoteJid.split('@')[0];
}

// Determinando whatsapp_bot (baseado no sender)
let whatsapp_bot = '';
if (sender) {
  whatsapp_bot = sender.split('@')[0];
}

// Determinando contato_user seguindo a hierarquia CORRIGIDA
