// Código para mapear e tratar mensagens ephemeral do WhatsApp no n8n

const webhookData = $input.all()[0].json;

// Função para mapear tipos de mensagens ephemeral
function mapEphemeralMessageType(data) {
  try {
    // Verifica se existe ephemeralMessage
    if (!data.body?.data?.message?.ephemeralMessage?.message) {
      return {
        isEphemeral: false,
        type: null,
        message: null,
        error: 'Não é uma mensagem ephemeral'
      };
    }

    const ephemeralMessage = data.body.data.message.ephemeralMessage.message;

    // Mapeia os tipos de mensagem ephemeral
    let messageType = null;
    let messageContent = null;

    // Verifica extendedTextMessage
    if (ephemeralMessage.extendedTextMessage) {
      messageType = 'extendedTextMessage';
      messageContent = ephemeralMessage.extendedTextMessage;
    }
    // Verifica documentMessage
    else if (ephemeralMessage.documentMessage) {
      messageType = 'documentMessage';
      messageContent = ephemeralMessage.documentMessage;
    }
    // Verifica outros tipos possíveis
    else if (ephemeralMessage.conversation) {
      messageType = 'conversation';
      messageContent = ephemeralMessage.conversation;
    }
    else if (ephemeralMessage.imageMessage) {
      messageType = 'imageMessage';
      messageContent = ephemeralMessage.imageMessage;
    }
    else if (ephemeralMessage.videoMessage) {
      messageType = 'videoMessage';
      messageContent = ephemeralMessage.videoMessage;
    }
    else if (ephemeralMessage.audioMessage) {
      messageType = 'audioMessage';
      messageContent = ephemeralMessage.audioMessage;
    }
    else if (ephemeralMessage.stickerMessage) {
      messageType = 'stickerMessage';
      messageContent = ephemeralMessage.stickerMessage;
    }
    else if (ephemeralMessage.locationMessage) {
      messageType = 'locationMessage';
      messageContent = ephemeralMessage.locationMessage;
    }
    else if (ephemeralMessage.contactMessage) {
      messageType = 'contactMessage';
      messageContent = ephemeralMessage.contactMessage;
    }
    else {
      messageType = 'unknown';
      messageContent = ephemeralMessage;
    }

    return {
      isEphemeral: true,
      type: messageType,
      message: messageContent,
      originalData: data.body.data.message.ephemeralMessage,
      error: null
    };

  } catch (error) {
    return {
      isEphemeral: false,
      type: null,
      message: null,
      error: `Erro ao processar mensagem ephemeral: ${error.message}`
    };
  }
}

// Função para tratar mensagens baseado no tipo
function processEphemeralMessage(mappedData) {
  if (!mappedData.isEphemeral) {
    return {
      processed: false,
      result: null,
      error: mappedData.error
    };
  }

  try {
    let processedResult = {
      messageType: mappedData.type,
      isEphemeral: true,
      timestamp: new Date().toISOString()
    };

    switch (mappedData.type) {
      case 'extendedTextMessage':
        processedResult = {
          ...processedResult,
          text: mappedData.message.text || '',
          contextInfo: mappedData.message.contextInfo || null,
          previewType: mappedData.message.previewType || null,
          title: mappedData.message.title || null,
          description: mappedData.message.description || null,
          canonicalUrl: mappedData.message.canonicalUrl || null,
          matchedText: mappedData.message.matchedText || null,
          jpegThumbnail: mappedData.message.jpegThumbnail || null
        };
        break;

      case 'documentMessage':
        processedResult = {
          ...processedResult,
          url: mappedData.message.url || null,
          mimetype: mappedData.message.mimetype || null,
          title: mappedData.message.title || null,
          fileSha256: mappedData.message.fileSha256 || null,
          fileLength: mappedData.message.fileLength || null,
          pageCount: mappedData.message.pageCount || null,
          mediaKey: mappedData.message.mediaKey || null,
          fileName: mappedData.message.fileName || null,
          fileEncSha256: mappedData.message.fileEncSha256 || null,
          directPath: mappedData.message.directPath || null,
          mediaKeyTimestamp: mappedData.message.mediaKeyTimestamp || null,
          contactVcard: mappedData.message.contactVcard || null,
          thumbnailDirectPath: mappedData.message.thumbnailDirectPath || null,
          thumbnailSha256: mappedData.message.thumbnailSha256 || null,
          thumbnailEncSha256: mappedData.message.thumbnailEncSha256 || null,
          jpegThumbnail: mappedData.message.jpegThumbnail || null,
          contextInfo: mappedData.message.contextInfo || null,
          caption: mappedData.message.caption || null
        };
        break;

      case 'conversation':
        processedResult = {
          ...processedResult,
          text: mappedData.message
        };
        break;

      case 'imageMessage':
      case 'videoMessage':
      case 'audioMessage':
        processedResult = {
          ...processedResult,
          url: mappedData.message.url || null,
          mimetype: mappedData.message.mimetype || null,
          fileSha256: mappedData.message.fileSha256 || null,
          fileLength: mappedData.message.fileLength || null,
          mediaKey: mappedData.message.mediaKey || null,
          fileEncSha256: mappedData.message.fileEncSha256 || null,
          directPath: mappedData.message.directPath || null,
          mediaKeyTimestamp: mappedData.message.mediaKeyTimestamp || null,
          jpegThumbnail: mappedData.message.jpegThumbnail || null,
          contextInfo: mappedData.message.contextInfo || null,
          caption: mappedData.message.caption || null
        };
        break;

      case 'locationMessage':
        processedResult = {
          ...processedResult,
          degreesLatitude: mappedData.message.degreesLatitude || null,
          degreesLongitude: mappedData.message.degreesLongitude || null,
          name: mappedData.message.name || null,
          address: mappedData.message.address || null,
          url: mappedData.message.url || null,
          jpegThumbnail: mappedData.message.jpegThumbnail || null,
          contextInfo: mappedData.message.contextInfo || null
        };
        break;

      case 'contactMessage':
        processedResult = {
          ...processedResult,
          displayName: mappedData.message.displayName || null,
          vcard: mappedData.message.vcard || null,
          contextInfo: mappedData.message.contextInfo || null
        };
        break;

      case 'stickerMessage':
        processedResult = {
          ...processedResult,
          url: mappedData.message.url || null,
          fileSha256: mappedData.message.fileSha256 || null,
          fileEncSha256: mappedData.message.fileEncSha256 || null,
          mediaKey: mappedData.message.mediaKey || null,
          mimetype: mappedData.message.mimetype || null,
          directPath: mappedData.message.directPath || null,
          fileLength: mappedData.message.fileLength || null,
          mediaKeyTimestamp: mappedData.message.mediaKeyTimestamp || null,
          isAnimated: mappedData.message.isAnimated || false,
          pngThumbnail: mappedData.message.pngThumbnail || null,
          contextInfo: mappedData.message.contextInfo || null
        };
        break;

      default:
        processedResult = {
          ...processedResult,
          rawMessage: mappedData.message,
          note: 'Tipo de mensagem não mapeado especificamente'
        };
        break;
    }

    return {
      processed: true,
      result: processedResult,
      error: null
    };

  } catch (error) {
    return {
      processed: false,
      result: null,
      error: `Erro ao processar mensagem do tipo ${mappedData.type}: ${error.message}`
    };
  }
}

// Executa o mapeamento e processamento
const mappedMessage = mapEphemeralMessageType(webhookData);
const processedMessage = processEphemeralMessage(mappedMessage);

// Resultado final
const finalResult = {
  isEphemeralMessage: mappedMessage.isEphemeral,
  messageType: mappedMessage.type,
  mappingSuccess: mappedMessage.error === null,
  processingSuccess: processedMessage.processed,
  data: processedMessage.result,
  errors: {
    mapping: mappedMessage.error,
    processing: processedMessage.error
  },
  originalWebhookData: webhookData,
  debug: {
    hasEphemeralMessage: !!webhookData.body?.data?.message?.ephemeralMessage,
    ephemeralMessageKeys: webhookData.body?.data?.message?.ephemeralMessage?.message ? 
      Object.keys(webhookData.body.data.message.ephemeralMessage.message) : [],
    timestamp: new Date().toISOString()
  }
};

// Retorna o resultado
return [finalResult];

