// Função para verificar se a mensagem é um "Oi"
function isOiMessage(mensagem) {
  if (!mensagem || typeof mensagem !== 'string') {
    return false;
  }

  let msg = mensagem.trim();

  // Remove padrões como "*NOME*:" ou "*NOME:" (com asterisco no início e/ou fim)
  msg = msg.replace(/^\*[^*:]*\*?\s*:\s*/g, '').trim();
  // Remove qualquer asterisco restante no início
  msg = msg.replace(/^\*\s*/g, '').trim();

  // Remove qualquer espaço em branco extra ou quebras de linha
  msg = msg.replace(/[\r\n\s]+/g, ' ').trim();

  // Verifica se o que sobrou é apenas "oi" (case insensitive)
  const textoLimpo = msg.toLowerCase().trim();

  return textoLimpo === 'oi' || 
         textoLimpo === 'oi!' || 
         textoLimpo === 'oi.' ||
         textoLimpo === 'oi?';
}

// Código para n8n
const mensagem = $('Dados_concatenados').first().json.Mensagem;
console.log('Mensagem original:', mensagem);
const resultado = isOiMessage(mensagem);

// Debug detalhado
let mensagemLimpa = mensagem || '';
mensagemLimpa = mensagemLimpa.replace(/^\*[^*:]*\*?\s*:\s*/g, '').trim();
mensagemLimpa = mensagemLimpa.replace(/^\*\s*/g, '').trim();
mensagemLimpa = mensagemLimpa.replace(/[\r\n\s]+/g, ' ').trim();
console.log('Mensagem limpa:', mensagemLimpa);
console.log('Resultado:', resultado);

return { 
  json: { 
    isOi: resultado,
    mensagemOriginal: mensagem,
    mensagemLimpa: mensagemLimpa
  } 
};
